class Admin_Model_CategoryLang extends Admin_Model_Base_CategoryLang {

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        $originalSlug = $this->slug;

        parent::save($conn);

        $modifiedSlug = $this->slug;
        if($originalSlug != $modifiedSlug) {
            try {
                if($originalSlug)
                CategorySlugHistory::addSlugHistory($this->Category_ID, $originalSlug);
            } catch (Exception $e) {
                // do nothing
            }
        }
    }

    public static function getLastRank() {
        $query = Doctrine_Query::create();
        $query->select('MAX(Rank) as Rank');
        $query->from('Admin_Model_CategoryLang');
        $result = $query->fetchOne();
        return $result['Rank'];
    }

}